class RangeModule {
    private TreeMap<Integer, Integer> ranges;

    public RangeModule() {
        ranges = new TreeMap<>();
    }

    public void addRange(int left, int right) {
        Integer start = ranges.floorKey(left);
        while (start != null && ranges.get(start) >= left) {
            start = ranges.lowerKey(start);
        }
        if (start != null) {
            left = Math.min(left, start);
            right = Math.max(right, ranges.get(start));
            ranges.remove(start);
        }
        while (!ranges.isEmpty() && ranges.firstKey() < right) {
            Map.Entry<Integer, Integer> entry = ranges.firstEntry();
            if (entry.getValue() >= left) {
                left = Math.min(left, entry.getKey());
                right = Math.max(right, entry.getValue());
                ranges.remove(entry.getKey());
            } else {
                break;
            }
        }
        ranges.put(left, right);
    }

    public boolean queryRange(int left, int right) {
        Integer start = ranges.floorKey(left);
        if (start == null || ranges.get(start) < left) {
            return false;
        }
        return ranges.get(start) >= right;
    }

    public void removeRange(int left, int right) {
        Integer start = ranges.floorKey(left);
        while (start != null && ranges.get(start) >= left) {
            start = ranges.lowerKey(start);
        }
        if (start != null) {
            if (ranges.get(start) > right) {
                ranges.put(right, ranges.get(start));
                ranges.put(start, left);
            } else {
                ranges.remove(start);
            }
        }
        start = ranges.ceilingKey(left);
        while (start != null && start < right) {
            Map.Entry<Integer, Integer> entry = ranges.ceilingEntry(start);
            if (entry.getValue() > right) {
                ranges.put(left, entry.getValue());
                ranges.remove(entry.getKey());
                break;
            } else {
                ranges.remove(entry.getKey());
            }
            start = ranges.ceilingKey(left);
        }
    }
}
